parameters.jsCode:
// Extract text content from HTML
const html = $input.item.json.data;
const postData = $('Webhook: Ghost Post Published').item.json.post.current;

// Simple HTML tag removal (n8n doesn't have DOM parser)
const textContent = html
  .replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '')
  .replace(/<style[^>]*>[\s\S]*?<\/style>/gi, '')
  .replace(/<[^>]+>/g, ' ')
  .replace(/\s+/g, ' ')
  .trim();

// Word count
const wordCount = textContent.split(/\s+/).length;

// Extract headings (approximate from title and structure)
const title = postData.title || '';
const excerpt = postData.excerpt || '';
const metaDescription = postData.meta_description || '';

return {
  json: {
    post_id: postData.id,
    post_url: postData.url,
    post_title: title,
    post_excerpt: excerpt,
    post_slug: postData.slug,
    meta_description: metaDescription,
    canonical_url: postData.canonical_url || postData.url,
    featured_image: postData.feature_image || '',
    tags: (postData.tags || []).map(t => t.name).join(', '),
    text_content: textContent.substring(0, 2000), // Limit for AI analysis
    word_count: wordCount,
    has_meta_description: metaDescription.length > 0,
    meta_description_length: metaDescription.length
  }
};

// Parse AI SEO analysis
const aiResponse = JSON.parse($input.item.json.response);
const postData = $('Code: Extract Content').item.json;

// Determine if we should auto-update Ghost post
const needsMetaUpdate = !postData.has_meta_description || postData.meta_description_length < 50;
const seoScore = aiResponse.seo_score;

return {
  json: {
    post_id: postData.post_id,
    post_url: postData.post_url,
    post_title: postData.post_title,
    current_meta_description: postData.meta_description,
    seo_score: seoScore,
    needs_meta_update: needsMetaUpdate,
    suggested_meta_description: aiResponse.suggested_meta_description,
    suggested_title: aiResponse.suggested_title,
    primary_keyword: aiResponse.primary_keyword,
    recommendations: aiResponse.recommendations,
    content_quality: aiResponse.content_quality,
    readability_score: aiResponse.readability_score,
    title_optimized: aiResponse.title_optimized,
    meta_description_optimized: aiResponse.meta_description_optimized
  }
};

